using namespace std;
inline int read()
{
	int x = 0, f = 1;
	char ch = getchar();
	while (ch < '0' || ch > '9')
	{
		if (ch == '-')f = -1;
		ch = getchar();
	}
	while (ch >= '0' && ch <= '9')x = x * 10 + ch - '0', ch = getchar();
	return x * f;
}
void write(int x)
{
	if (x < 0)putchar('-'), x = -x;
	if (x > 9)write(x / 10);
	putchar(x % 10 + '0');
	return;
}
int m, n, a[21], sum, flag, q;
void dfs(int a1, int a2, int a3, int a4, int k)
{
	if (flag)return;
	if (a1 > q || a2 > q || a3 > q || a4 > q)return;
	if (k == m + 1 && a1 == q && a2 == q && a3 == q && a4 == q)
	{
		flag = 1;
		return;
	}
	if (k == m + 1)return;
	dfs(a1 + a[k], a2, a3, a4, k + 1);
	dfs(a1, a2 + a[k], a3, a4, k + 1);
	dfs(a1, a2, a3 + a[k], a4, k + 1);
	dfs(a1, a2, a3, a4 + a[k], k + 1);
	return;
}
int main(void)
{
	//freopen("xx.in","r",stdin);
	//freopen("xx.out","w",stdout);
	cin>>n;
	while(n--)
	{
		cin >> m;
		for (int i = 1; i <= m; ++i)a[i]=read();
		sum = 0;
		for (int i = 1; i <= m; ++i)sum += a[i];
		q = sum / 4;
		sort(a + 1, a + m + 1, greater<int>());
		flag = 0;
		dfs(0, 0, 0, 0, 1);
		if (flag)puts("yes");
		else puts("no");
	}
	return false;
}
